import json

def check_format(answer: str, case: dict) -> bool:
    """Verify structured output format requirements."""
    if case.get("expected_format") == "json":
        try:
            obj = json.loads(answer)
        except json.JSONDecodeError:
            return False  # Not valid JSON
        required_keys = case.get("required_keys", [])
        return all(k in obj for k in required_keys)
    # For prose format, delegate to LLM judge
    return True  # handled by check_answer()
